mapper.select:
SELECT T1.ID AS id, T1.SUPPLIER_CODE AS supplierCode, T1.COMPANY_ID AS companyId, T1.CUSTOMER_TYPE AS customerType, T1.SUPPLIER_NAME AS supplierName, DBMS_LOB.SUBSTR(T1.COMPANY_NAME, 4000, 1) AS companyName, DBMS_LOB.SUBSTR(T1.COMPANY_SHORT, 4000, 1) AS companyShort, DBMS_LOB.SUBSTR(T1.FORMER_NAME, 4000, 1) AS formerName, DBMS_LOB.SUBSTR(T1.E_COMPANY_NAME, 4000, 1) AS eCompanyName, T1.INDUSTRY_TYPE AS industryType, T1.COUNTRY AS country, T1.PROVINCE AS province, T1.CITY AS city, T1.REGISTERED_CURRENCY AS registeredCurrency, DBMS_LOB.SUBSTR(T1.ADDRESS, 4000, 1) AS address, T1.UNIFORM_SOCIAL_CREDIT_CODE AS uniformSocialCreditCode, T1.ORGANIZATION_CODE AS organizationCode, T1.BUSINESS_TYPE AS businessType, T1.DUNS AS duns, T1.MNEMONIC_CODE AS mnemonicCode, T1.ESTIBLISH_TIME AS estiblishTime, T1.REGISTERED_CAPITAL AS registeredCapital, T1.LEGAL_PERSON AS legalPerson, T1.LEGAL_PERSON_CARD_NO AS legalPersonCardNo, T1.BUSINESS_STATE AS businessState, DBMS_LOB.SUBSTR(T1.BUSINESS_SCOPE, 4000, 1) AS businessScope, T1.COMPANY_TEL AS companyTel, DBMS_LOB.SUBSTR(T1.BUSINESS_ADDRESS, 4000, 1) AS businessAddress, T1.LICENSEIMG_URL AS licenseImgUrl, DBMS_LOB.SUBSTR(T1.LEGAL_PERSON_CARD_IMG1, 4000, 1) AS legalPersonCardImg1, DBMS_LOB.SUBSTR(T1.LEGAL_PERSON_CARD_IMG2, 4000, 1) AS legalPersonCardImg2, T1.IS_AUTH AS isAuth, T1.STATE AS status, DBMS_LOB.SUBSTR(T1.REMARK, 4000, 1) AS remark, DBMS_LOB.SUBSTR(T1.COMPANY_INFO_REMARK, 4000, 1) AS companyInfoRemark, DBMS_LOB.SUBSTR(T1.SUPPLIER_PERSON, 4000, 1) AS supplierPerson, DBMS_LOB.SUBSTR(T1.SUPPLIER_PHONE, 4000, 1) AS supplierPhone, DBMS_LOB.SUBSTR(T1.RELATION_VOID_PERSON, 4000, 1) AS relationVoidPerson, DBMS_LOB.SUBSTR(T1.RELATION_VOID_REASON, 4000, 1) AS relationVoidReason, T1.CREATED_USER AS createBy, T1.CREATED_TIME AS createTime, T1.UPDATE_USER AS updateBy, T1.UPDATE_TIME AS updateTime FROM E_MATERIAL_SUPPLIER T1 WHERE T1.CUSTOMER_TYPE = '1' AND T1.RELATION_VOID_DATE IS NULL
AND T1.SUPPLIER_CODE LIKE #{supplierCodeLike}
AND T1.SUPPLIER_NAME LIKE #{supplierNameLike}
AND T1.UNIFORM_SOCIAL_CREDIT_CODE LIKE #{uniformSocialCreditCodeLike}
AND T1.BUSINESS_TYPE LIKE #{businessTypeLike}
AND T1.STATE = #{status}
ORDER BY T1.CREATED_TIME DESC, T1.ID DESC

SELECT COUNT(1)
FROM E_MATERIAL_SUPPLIER
WHERE CUSTOMER_TYPE = '1'
AND RELATION_VOID_DATE IS NULL
AND SUPPLIER_NAME = #{supplierName}
AND UNIFORM_SOCIAL_CREDIT_CODE = #{uniformSocialCreditCode}

    AND ID <> #{excludeId}
